content:
{
  "sentences": [
    {
      "text": "這件上衣的尺寸是M號嗎？",
      "pinyin": "Zhè jiàn shàngyī de chǐcùn shì M hào ma?",
      "pinyin_numeric": "zhe4 jian4 shang4yi1 de5 chi3cun4 shi4 M hao4 ma0",
      "translation_en": "Is this shirt size M?",
      "translation_ko": "이 상의 사이즈가 M인가요?"
    },
    {
      "text": "我穿L號，這件褲子太小了。",
      "pinyin": "Wǒ chuān L hào, zhè jiàn kùzi tài xiǎo le.",
      "pinyin_numeric": "wo3 chuan1 L hao4, zhe4 jian4 ku4zi5 tai4 xiao3 le5",
      "translation_en": "I wear size L; these pants are too small.",
      "translation_ko": "저는 L 사이즈를 입는데, 이 바지는 너무 작아요."
    },
    {
      "text": "這件外套有黑色的嗎？",
      "pinyin": "Zhè jiàn wàitào yǒu hēisè de ma?",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 you3 hei1se4 de5 ma0",
      "translation_en": "Does this jacket come in black?",
      "translation_ko": "이 외투는 검은색이 있나요?"
    },
    {
      "text": "我想試穿這件藍色的裙子。",
      "pinyin": "Wǒ xiǎng shìchuān zhè jiàn lánsè de qúnzi.",
      "pinyin_numeric": "wo3 xiang3 shi4chuan1 zhe4 jian4 lan2se4 de5 qun2zi5",
      "translation_en": "I want to try on this blue skirt.",
      "translation_ko": "이 파란색 치마를 입어보고 싶어요."
    },
    {
      "text": "這雙鞋子有白色的嗎？",
      "pinyin": "Zhè shuāng xiézi yǒu báisè de ma?",
      "pinyin_numeric": "zhe4 shuang1 xie2zi5 you3 bai2se4 de5 ma0",
      "translation_en": "Do these shoes come in white?",
      "translation_ko": "이 신발은 흰색이 있나요?"
    },
    {
      "text": "這件衣服的尺寸太大了，有沒有小號的？",
      "pinyin": "Zhè jiàn yīfu de chǐcùn tài dà le, yǒu méiyǒu xiǎo hào de?",
      "pinyin_numeric": "zhe4 jian4 yi1fu5 de5 chi3cun4 tai4 da4 le5, you3 mei2you3 xiao3 hao4 de5",
      "translation_en": "This clothing is too big; do you have a small size?",
      "translation_ko": "이 옷 사이즈가 너무 큰데, 작은 사이즈가 있나요?"
    },
    {
      "text": "這件褲子穿起來很舒服，可是顏色不適合我。",
      "pinyin": "Zhè jiàn kùzi chuān qǐlái hěn shūfú, kěshì yánsè bù shìhé wǒ.",
      "pinyin_numeric": "zhe4 jian4 ku4zi5 chuan1 qi3lai2 hen3 shu1fu2, ke3shi4 yan2se4 bu4 shi4he2 wo3",
      "translation_en": "These pants are comfortable to wear, but the color doesn't suit me.",
      "translation_ko": "이 바지는 입기에 편한데, 색상이 저에게 안 어울려요."
    },
    {
      "text": "這件外套現在打折，原價一千塊，現在只要七百塊。",
      "pinyin": "Zhè jiàn wàitào xiànzài dǎzhé, yuánjià yīqiān kuài, xiànzài zhǐyào qībǎi kuài.",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 xian4zai4 da3zhe2, yuan2jia4 yi1qian1 kuai4, xian4zai4 zhi3yao4 qi1bai3 kuai4",
      "translation_en": "This jacket is on sale now; the original price was 1000 dollars, now it's only 700.",
      "translation_ko": "이 외투는 지금 할인 중이에요. 정가는 1000위안인데, 지금은 700위안이에요."
    },
    {
      "text": "這件上衣的材質是棉的，穿起來很舒服。",
      "pinyin": "Zhè jiàn shàngyī de cáizhì shì mián de, chuān qǐlái hěn shūfú.",
      "pinyin_numeric": "zhe4 jian4 shang4yi1 de5 cai2zhi4 shi4 mian2 de5, chuan1 qi3lai2 hen3 shu1fu2",
      "translation_en": "This shirt is made of cotton; it's very comfortable to wear.",
      "translation_ko": "이 상의는 소재가 면이라서 입기에 아주 편해요."
    },
    {
      "text": "請問，試衣間在哪裡？我想試穿這件褲子。",
      "pinyin": "Qǐngwèn, shìyījiān zài nǎlǐ? Wǒ xiǎng shìchuān zhè jiàn kùzi.",
      "pinyin_numeric": "qing3wen4, shi4yi1jian1 zai4 na3li3? wo3 xiang3 shi4chuan1 zhe4 jian4 ku4zi5",
      "translation_en": "Excuse me, where is the fitting room? I want to try on these pants.",
      "translation_ko": "실례합니다. 탈의실이 어디에 있나요? 이 바지를 입어보고 싶어요."
    }
  ]
}
